const drawVertical = useCallback(() => {
  const svg = d3.select(svgVerticalRef.current);
  svg.selectAll('*').remove();
  if (verticalChain.length === 0) return;

  // ✅ Increased box dimensions to prevent name cutting
  const boxW = 320, boxH = 220, nodeW = 360, nodeH = 260, padding = 200;

  const root = d3.hierarchy(verticalChain.reduceRight((child, node) => ({ ...node, children: child ? [child] : [] })));
  const treeLayout = d3.tree().nodeSize([nodeW, nodeH]);
  treeLayout(root);

  const descendants = root.descendants();
  const links = root.links();
  const minX = d3.min(descendants, d => d.x) - boxW / 2, maxX = d3.max(descendants, d => d.x) + boxW / 2;
  const minY = d3.min(descendants, d => d.y) - boxH / 2, maxY = d3.max(descendants, d => d.y) + boxH / 2;
  const width = maxX - minX + padding * 2, height = maxY - minY + padding * 2;

  svg.attr('width', width).attr('height', height).attr('viewBox', `0 0 ${width} ${height}`);
  const defs = svg.append('defs');
  const gradient = defs.append('linearGradient').attr('id', 'vertGradient').attr('x1', '0%').attr('y1', '0%').attr('x2', '0%').attr('y2', '100%');
  gradient.append('stop').attr('offset', '0%').attr('stop-color', '#2E7D32');
  gradient.append('stop').attr('offset', '50%').attr('stop-color', '#c9a84c');
  gradient.append('stop').attr('offset', '100%').attr('stop-color', '#2E7D32');

  const g = svg.append('g').attr('transform', `translate(${padding - minX}, ${padding - minY})`);
  const zoomBeh = d3.zoom().scaleExtent([0.1, 12]).on('zoom', e => { g.attr('transform', `translate(${e.transform.x}, ${e.transform.y}) scale(${e.transform.k})`); });
  svg.call(zoomBeh);
  const init = d3.zoomIdentity.translate(width / 2 - (minX + maxX) / 2, height / 2 - (minY + maxY) / 2).scale(1);
  svg.call(zoomBeh.transform, init);
  zoomRef.current = zoomBeh;

  g.selectAll('.link').data(links, d => d.target.data.id)
    .join('path').attr('fill', 'none').attr('stroke', 'url(#vertGradient)').attr('stroke-width', 2.5)
    .attr('d', d => {
      const sx = d.source.x, sy = d.source.y + boxH / 2;
      const tx = d.target.x, ty = d.target.y - boxH / 2;
      const my = (sy + ty) / 2;
      return `M${sx},${sy} L${sx},${my} L${tx},${my} L${tx},${ty}`;
    });

  const nodeGroup = g.selectAll('.node').data(descendants, d => d.data.id)
    .join('g').attr('class', 'node').attr('transform', d => `translate(${d.x - boxW / 2}, ${d.y - boxH / 2})`);

  nodeGroup.append('rect').attr('width', boxW).attr('height', boxH).attr('rx', 12).attr('ry', 12)
    .attr('fill', '#ffffffcc').attr('stroke', '#2E7D32').attr('stroke-width', 2.5);
  nodeGroup.append('rect').attr('width', boxW).attr('height', 6).attr('rx', 3).attr('fill', '#2E7D32');

  nodeGroup.append('foreignObject').attr('width', boxW - 20).attr('height', boxH - 70).attr('x', 10).attr('y', 10)
    .append('xhtml:div').style('width', '100%').style('height', '100%')
    .style('display', 'flex').style('flex-direction', 'column').style('align-items', 'center').style('justify-content', 'center')
    .style('text-align', 'center').style('font-size', '11px')   // slightly smaller font
    .html(d => {
      const father = getFatherName(d.data);
      const fatherLine = father ? `<br/><span style="font-size:9px;color:#1565C0;">بن ${father}</span>` : '';
      // Wife names – if multiple, they are separated by commas or stored as a single string
      const wives = d.data.wife_name ? d.data.wife_name.split(',').map(w => w.trim()).join('، ') : '';
      const wifeLine = wives ? `<br/><span style="font-size:9px;color:#C2185B;">زوجہ: ${wives}</span>` : '';
      return `<b>${d.data.name}</b>${fatherLine}${wifeLine}<br/><span style="font-size:9px;color:#555;">پشت: ${d.data.generation_number}</span>${d.data.info ? `<br/><span style="font-size:9px;color:#777;">${d.data.info}</span>` : ''}`;
    });

  // Icons (child, sibling, spouse) + edit/delete
  if (isAdmin) {
    nodeGroup.each(function(d) {
      const gNode = d3.select(this);
      const btnY = boxH - 32;

      gNode.append('g').attr('transform', `translate(18, ${btnY})`).attr('cursor', 'pointer')
        .on('click', (e) => { e.stopPropagation(); handleAddChild(d.data); })
        .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12).attr('fill', '#fff').attr('stroke', '#2E7D32').attr('stroke-width', 1.4);
      gNode.select('g:last-child').append('text').attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
        .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#2E7D32').text('⬇️')
        .append('title').text('Child add karein');

      gNode.append('g').attr('transform', `translate(${boxW / 2 - 23}, ${btnY})`).attr('cursor', 'pointer')
        .on('click', (e) => { e.stopPropagation(); handleAddSibling(d.data); })
        .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12).attr('fill', '#fff').attr('stroke', '#1565C0').attr('stroke-width', 1.4);
      gNode.select('g:last-child').append('text').attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
        .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#1565C0').text('↔️')
        .append('title').text('Sibling add karein');

      gNode.append('g').attr('transform', `translate(${boxW - 64}, ${btnY})`).attr('cursor', 'pointer')
        .on('click', (e) => { e.stopPropagation(); handleAddSpouse(d.data); })
        .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12).attr('fill', '#fff').attr('stroke', '#C2185B').attr('stroke-width', 1.4);
      gNode.select('g:last-child').append('text').attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
        .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#C2185B').text('💍')
        .append('title').text('Spouse add karein');

      // Edit & Delete buttons (top-right)
      gNode.append('g').attr('transform', `translate(${boxW - 120}, 6)`).attr('cursor', 'pointer')
        .on('click', (e) => { e.stopPropagation(); handleEdit(d.data); })
        .append('rect').attr('width', 26).attr('height', 18).attr('rx', 8).attr('fill', '#fff').attr('stroke', '#1565C0').attr('stroke-width', 1.2);
      gNode.select('g:last-child').append('text').attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
        .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#1565C0').text('✎');

      gNode.append('g').attr('transform', `translate(${boxW - 80}, 6)`).attr('cursor', 'pointer')
        .on('click', (e) => { e.stopPropagation(); handleDelete(d.data); })
        .append('rect').attr('width', 26).attr('height', 18).attr('rx', 8).attr('fill', '#fff').attr('stroke', '#C2185B').attr('stroke-width', 1.2);
      gNode.select('g:last-child').append('text').attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
        .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#C2185B').text('✕');
    });
  }
}, [verticalChain, isAdmin, getFatherName, handleAddChild, handleAddSibling, handleAddSpouse, handleEdit, handleDelete]);
